import React, { useState } from "react";
import {
  AccountInfo,
  Configuration,
  PublicClientApplication,
  AuthError,
  InteractionType,
} from "@azure/msal-browser";
import {
  AuthenticatedTemplate,
  IMsalContext,
  UnauthenticatedTemplate,
  useMsal,
} from "@azure/msal-react";
import logo from "./logo.png";
import "../App.css";
import nameslogan from "./nameslogan1.png";
import {
  Box,DialogContentText,DialogContent,DialogActions,Dialog,DialogTitle,Button
} from '@mui/material';

const MicrosoftLoginButton: React.FC = () => {
  const { instance } = useMsal();
  const [showAboutModal, setShowAboutModal] = useState(false);

  const Abc = () => {
    instance.loginRedirect();
  };

  const toggleAboutModal = () => {
    setShowAboutModal(!showAboutModal);
  };

  const [account, setAccount] = useState<AccountInfo | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);

  const [openDialog, setOpenDialog] = React.useState(false);

  const handleClickOpen = () => {
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
  };

  const [openDialog1, setOpenDialog1] = useState(false);

  const handleOpenMyDialog = () => {
    setOpenDialog1(true);
  };

  const handleCloseMyDialog = () => {
    setOpenDialog1(false);
  };

  return (
    <div>
      <AuthenticatedTemplate>
        <div>
          <p>ahaahaaha</p> {/* 这一段是登录之后要跳转的画面，游客登录的跳转我没有写（包括按钮上没有带onclick） */}
        </div>
      </AuthenticatedTemplate>

      <UnauthenticatedTemplate>

      <div>
        <img 
          src={nameslogan}
          alt="name"
          style={{ width: "600px", height: "auto", marginTop:'260px',marginLeft:'100px'}}
        />{/* name */}
      </div>  

   <div>
    <img 
      src={logo}
      alt="logo"
      style={{ width: "220px", height: "auto", marginTop:'-490px',marginLeft:'920px'}}
    />{/* logo */}
  </div>

  <div className="button-container" style={{ display: 'flex', alignItems: 'center' }}>
        <Button
          variant="contained"
          sx={{ mb: 2, marginTop: 38, marginLeft: -104 }}
          onClick={handleOpenMyDialog}
        >
          LOGIN
        </Button>

      <Dialog
        open={openDialog1}
        onClose={handleCloseMyDialog}
        aria-labelledby="alert-dialog-title"
        aria-describedby="alert-dialog-description"
      >
        <DialogTitle
          id="alert-dialog-title"
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
          }}
        >
          {"LOGIN"}
        </DialogTitle>
        <DialogContent>
          <DialogContentText id="alert-dialog-description">
            You can keep selection records for future reference with Microsoft.
          </DialogContentText>
        </DialogContent>
        <DialogActions
          sx={{
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            alignItems: 'center',
            margin: '10px 20px',
          }}
        >
          <Button onClick={Abc} variant="contained">
            Login with Microsoft
          </Button>
          <br></br>
          <Button variant="outlined" sx={{ width: '212px',marginRight:1}}>
            Login as visitor
          </Button>
          <br></br>
          <Button onClick={handleCloseMyDialog} autoFocus>
            Close
          </Button>
          {accessToken && <p>Access Token: {accessToken}</p>}
        </DialogActions>
      </Dialog>

      <Button
        onClick={handleClickOpen}
        variant="outlined"
        sx={{ mb: 2, marginTop: 38, marginLeft: 5 }}
      >
        About
      </Button>
</div>
</UnauthenticatedTemplate>


      {/* 以下是About和它绑的内容 */}
      <Dialog
        open={openDialog}
        onClose={handleCloseDialog}
        aria-labelledby="alert-dialog-title"
        aria-describedby="alert-dialog-description"
      >
        <DialogTitle id="alert-dialog-title">{"About"}</DialogTitle>
        <DialogContent>
          <DialogContentText id="alert-dialog-description">
          <p>If you have choice difficulties like the developers of this website, you have made the right choice by entering here. Comparealm can help to reflect your inner thoughts and guide you to make the destined soul choice as long as you type the item or person or anything you can think of to choose. Let's make your decision here and now.</p>
            <br></br>
            <p>Our aim is to use the most rational way to reflect the most correct choices in the hearts of users, and to help them minimize detours to the greatest extent possible. The definition of options in society is not important, YOU are the true center of the vortex.</p>
            <br></br>
            <p>Logo meaning: Difficulty in choosing is no different from an infinite cycle of Mobius rings. Comparealm is committed to breaking the cycle and allowing users to see one big circle, two circles, or more possibilities.</p>
            <br></br>
            <p>Developer team message: Perhaps Comparealm also supports you to compare us with other websites?[doge]</p>
          </DialogContentText>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog} autoFocus>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>

    </div>
  );
};

export default MicrosoftLoginButton;
