import React from 'react';
import ReactDOM from 'react-dom';
import  App  from './App';
import { mergeStyles } from '@fluentui/react';
import reportWebVitals from './reportWebVitals';
import { AccountInfo, Configuration, PublicClientApplication, AuthError } from "@azure/msal-browser";
import { IMsalContext,MsalProvider} from "@azure/msal-react";

const msalConfig: Configuration = {
  auth: {
    clientId: 'b509e267-37ac-4fd3-93e2-f2cfbe18ca6a', // 您提供的 Azure 应用程序客户端 ID
    redirectUri: 'http://localhost:3000'
  },
};

const pca = new PublicClientApplication(msalConfig);

const Choice = ()=>(
  <MsalProvider instance ={pca}>
    <App />
  </MsalProvider>
);

// Inject some global styles
mergeStyles({
  ':global(body,html,#root)': {
    margin: 0,
    padding: 0,
    height: '100vh',
  },
});

ReactDOM.render(<Choice />, document.getElementById('root'));

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
